insert into content_items (title, body, category, states, min_age, action_line, source_url, published_at, expires_at, status) values
('Medicare Open Enrollment runs Oct 15-Dec 7', 'Plans can change premiums, drug coverage, pharmacies, and out-of-pocket costs every year. Re-shop your plan during this window even if you are happy with last year''s choice.', 'medicare', null, 63, 'Ask: Should I compare my current plan against next year''s prescriptions and doctors?', 'https://www.medicare.gov/plan-compare/', '2026-10-15T09:00:00Z', '2026-12-08T05:00:00Z', 'approved'),
('Medicare Open Enrollment final week', 'December 7 is the scheduled deadline for most Open Enrollment changes that begin January 1.', 'medicare', null, 63, 'Ask: Have I checked drug tiers, preferred pharmacies, and annual out-of-pocket limits?', 'https://www.medicare.gov/plan-compare/', '2026-12-01T09:00:00Z', '2026-12-08T05:00:00Z', 'approved'),
('Annual Notice of Change review', 'Medicare Advantage and Part D plans send Annual Notice of Change materials before Open Enrollment. Small formulary or network changes can matter.', 'medicare', null, 63, 'Ask: What changed in my plan for the coming year?', 'https://www.medicare.gov/basics/forms-publications-mailings/mailings/plan-notices', '2026-09-15T09:00:00Z', '2026-12-08T05:00:00Z', 'approved'),
('IRMAA two-year lookback reminder', 'Medicare IRMAA surcharges generally use income from two years earlier. Roth conversions, capital gains, or large withdrawals can affect future premiums.', 'medicare', null, 63, 'Ask: Could this year''s taxable income push a future Medicare premium surcharge?', 'https://www.ssa.gov/medicare/lower-irmaa', '2026-06-01T09:00:00Z', null, 'published'),
('Extra Help with Medicare drug costs', 'People with limited income and resources may qualify for Extra Help with prescription drug costs. Applying is free.', 'medicare', null, 64, 'Ask: Should I screen for Extra Help or state pharmaceutical assistance?', 'https://www.ssa.gov/medicare/part-d-extra-help', '2026-01-10T09:00:00Z', null, 'published'),
('October Social Security COLA watch', 'Social Security''s annual cost-of-living adjustment is typically announced in October. Update your budget once your new benefit amount is available.', 'ss', null, 60, 'Ask: What will my net monthly deposit be after Medicare premiums?', 'https://www.ssa.gov/cola/', '2026-10-01T09:00:00Z', '2026-11-15T05:00:00Z', 'approved'),
('Check your my Social Security account', 'Your statement can help estimate retirement benefits before claiming and verify earnings history.', 'ss', null, 60, 'Ask: Does my earnings record look complete before I rely on this estimate?', 'https://www.ssa.gov/myaccount/', '2026-02-01T09:00:00Z', null, 'published'),
('Social Security claiming window', 'Claiming before full retirement age reduces monthly benefits; delaying up to age 70 can increase them. Survivor and spouse context can matter.', 'ss', null, 60, 'Ask: Have I compared age 62, full retirement age, and age 70 for my household?', 'https://www.ssa.gov/benefits/retirement/planner/agereduction.html', '2026-03-01T09:00:00Z', null, 'published'),
('RMD deadline reminder', 'Required minimum distributions generally must be taken by December 31 once RMD rules apply. Verify amounts and withholding early.', 'tax', null, 72, 'Ask: Have I confirmed every IRA and workplace-plan RMD?', 'https://www.irs.gov/retirement-plans/retirement-plan-and-ira-required-minimum-distributions-faqs', '2026-11-15T09:00:00Z', '2027-01-01T05:00:00Z', 'approved'),
('First RMD timing check', 'Your first RMD may have special timing rules. Delaying the first one can bunch two taxable distributions into the same year.', 'tax', null, 72, 'Ask: Would delaying a first RMD increase taxes or Medicare premium risk?', 'https://www.irs.gov/retirement-plans/retirement-plan-and-ira-required-minimum-distributions-faqs', '2026-04-01T09:00:00Z', null, 'published'),
('Tax-year change checklist', 'New brackets, deductions, contribution limits, and Medicare premiums can shift cash-flow math each January.', 'tax', null, null, 'Ask: Do withholding, estimated taxes, or planned withdrawals need a January refresh?', 'https://www.irs.gov/newsroom', '2027-01-02T09:00:00Z', '2027-03-31T04:00:00Z', 'approved'),
('Quarterly estimated tax date check', 'Retirees with IRA withdrawals, self-employment income, interest, or capital gains may need estimated tax payments or withholding.', 'tax', null, null, 'Ask: Am I relying on withholding or quarterly payments to avoid surprises?', 'https://www.irs.gov/businesses/small-businesses-self-employed/estimated-taxes', '2026-03-15T09:00:00Z', null, 'published'),
('Gift-card scam targeting Social Security recipients', 'Callers claiming to be from Social Security may demand payment in gift cards or threaten arrest. Government agencies do not demand gift cards.', 'scam', null, 60, 'What to do: Hang up and report suspicious Social Security contacts through official channels.', 'https://oig.ssa.gov/report/', '2026-01-15T09:00:00Z', null, 'published'),
('Medicare impostor calls before Open Enrollment', 'Scammers pose as Medicare to verify numbers or sell plans. Do not give your Medicare number to unsolicited callers.', 'scam', null, 63, 'What to do: Use Medicare.gov or call 1-800-MEDICARE from a trusted source.', 'https://www.medicare.gov/basics/reporting-medicare-fraud-and-abuse', '2026-09-01T09:00:00Z', '2026-12-15T05:00:00Z', 'approved'),
('Bank impersonation text alert', 'Texts that link to a fake bank login can steal credentials. Use your bank app or the number on your card instead of a link.', 'scam', null, null, 'What to do: Do not tap the link; verify inside your bank app or by calling the card number.', 'https://consumer.ftc.gov/articles/how-recognize-and-report-spam-text-messages', '2026-02-10T09:00:00Z', null, 'published'),
('Grandparent scam verification step', 'Urgent calls claiming a family emergency often pressure secrecy and immediate payment. Verify through a known family number.', 'scam', null, 60, 'What to do: Pause and call the family member or another trusted contact directly.', 'https://consumer.ftc.gov/articles/family-emergency-scams', '2026-02-20T09:00:00Z', null, 'published'),
('California senior scam bulletin watch', 'State and local agencies regularly warn older Californians about contractor, utility, and impostor scams after storms and disasters.', 'scam', '{CA}', 60, 'What to do: Verify licenses and never pay an unsolicited contractor in cash upfront.', 'https://oag.ca.gov/consumers', '2026-05-01T09:00:00Z', null, 'published'),
('Florida hurricane repair scam watch', 'After severe weather, fake contractors may solicit urgent repairs. Verify licensing and avoid high-pressure upfront payments.', 'scam', '{FL}', 60, 'What to do: Check contractor credentials and get written estimates before paying.', 'https://www.myfloridalegal.com/consumer-protection', '2026-06-01T09:00:00Z', '2026-12-01T05:00:00Z', 'published'),
('Texas utility impostor warning', 'Utility impostors may threaten shutoff unless you pay immediately by gift card, crypto, or payment app.', 'scam', '{TX}', 60, 'What to do: Call the utility using the number on your bill before making any payment.', 'https://www.texasattorneygeneral.gov/consumer-protection', '2026-07-01T09:00:00Z', null, 'published'),
('Inflation budget refresh', 'Food, insurance, utilities, and medical costs do not rise at the same pace. Review your own basket instead of relying only on headline inflation.', 'inflation', null, null, 'Ask: Which two spending categories are most likely to pressure my monthly plan?', 'https://www.bls.gov/cpi/', '2026-04-15T09:00:00Z', null, 'published'),
('Insurance premium re-shop reminder', 'Home and auto insurance premiums can rise sharply. Annual re-shopping and discount checks may protect cash flow.', 'inflation', null, null, 'Ask: Should I compare deductibles, coverage, bundling, and senior or low-mileage discounts?', 'https://content.naic.org/consumer.htm', '2026-05-15T09:00:00Z', null, 'published'),
('Prescription cost review', 'Drug prices and formularies can change. Before refills get expensive, compare generics, preferred pharmacies, and assistance programs.', 'inflation', null, 60, 'Ask: Are any prescriptions moving tiers or becoming cheaper through another pharmacy?', 'https://www.medicare.gov/plan-compare/', '2026-08-01T09:00:00Z', null, 'published'),
('Texas property-tax relief for seniors', 'Texas offers homestead-related property-tax protections for many homeowners 65 and older. Rules and filing details run through local appraisal districts.', 'tax', '{TX}', 65, 'Ask: Have I applied for every county homestead or over-65 exemption available?', 'https://comptroller.texas.gov/taxes/property-tax/exemptions/', '2026-01-20T09:00:00Z', null, 'published'),
('Florida additional senior homestead exemption', 'Some Florida counties and cities offer an additional homestead exemption for residents 65 and older who meet income limits.', 'tax', '{FL}', 65, 'Ask: Does my county offer an additional senior exemption and what is the deadline?', 'https://floridarevenue.com/property/Pages/Taxpayers_Exemptions.aspx', '2026-01-20T09:00:00Z', null, 'published'),
('New York Enhanced STAR reminder', 'New York homeowners 65 and older under the income limit may qualify for Enhanced STAR property-tax relief.', 'tax', '{NY}', 65, 'Ask: Do I need to enroll or verify income to keep Enhanced STAR?', 'https://www.tax.ny.gov/pit/property/star/', '2026-01-20T09:00:00Z', null, 'published'),
('LIHEAP seasonal utility help', 'The Low Income Home Energy Assistance Program may help eligible households with heating or cooling costs. Funding and windows vary by state.', 'benefit', null, null, 'Ask: Should I screen for energy assistance before peak heating or cooling bills?', 'https://www.acf.hhs.gov/ocs/programs/liheap', '2026-01-05T09:00:00Z', null, 'published');
